    def __init__(self):
        self.cells = {}

    def set_cell(self, cell: str, value: int | str):
        self.cells[cell] = value

    def get_cell(self, cell: str) -> int:
        value = self.cells[cell]
        if isinstance(value, str) and value.startswith('='):
            formula = value[2:].split()
            result = self.evaluate_formula(formula)
            self.set_cell(cell, result)
            return result
        else:
            return value

    def evaluate_formula(self, formula: list[str]) -> int:
        stack = []
        operators = {'+': lambda a, b: a + b,
                     '-': lambda a, b: a - b,
                     '*': lambda a, b: a * b,
                     '/': lambda a, b: a / b}

        for token in formula:
            if token in operators:
                b = stack.pop()
                a = stack.pop()
                stack.append(int(operators[token](a, b)))
            else:
                stack.append(self.get_cell(token))

        return int(stack.pop())

